  @property({ type: String }) label = '';
  @property({ type: String }) color = '#ff9f00';
  @property({ type: String }) defaultPrompt = '';
  @property({ type: Object }) engine!: LyriaEngine;

  @state() private promptText = '';
  @state() private weight = 0.5;

