import { GoogleGenAI } from '@google/genai';
import { LyriaSequencer } from './components/LyriaSequencer';
import { ToastMessage } from './components/ToastMessage';
import { LyriaEngine } from './utils/LyriaEngine';
import { AudioAnalyser } from './utils/AudioAnalyser';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const model = 'lyria-realtime-exp';

function main() {
  const engine = new LyriaEngine(ai, model);
  const analyser = new AudioAnalyser(engine.audioContext);
  engine.extraDestination = analyser.node;

  // Use document.createElement or ensure the custom element is recognized
  const sequencer = document.createElement('lyria-sequencer') as LyriaSequencer;
  sequencer.engine = engine;
  document.body.appendChild(sequencer);

  const toast = document.createElement('toast-message') as ToastMessage;
  document.body.appendChild(toast);

  engine.addEventListener('error', (e: any) => toast.show(e.detail));
  engine.addEventListener('info', (e: any) => toast.show(e.detail));

  analyser.addEventListener('audio-level-changed', (e: any) => {
    sequencer.audioLevel = e.detail;
  });

  // Fix: AudioAnalyser.start is a reference to loop, called without arguments
  analyser.start();
}

main();

