@customElement('analog-knob')
export class AnalogKnob extends LitElement {
  // Fix: Removed incorrect override
  static styles = css`
    :host {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 8px;
    }
    .knob-container {
      width: 50px;
      height: 50px;
      position: relative;
      cursor: ns-resize;
    }
    .knob-body {
      width: 100%;
      height: 100%;
      background: radial-gradient(circle, #444 0%, #222 100%);
      border: 2px solid #111;
      border-radius: 50%;
      position: relative;
    }
    .knob-indicator {
      width: 4px;
      height: 12px;
      background: #ff9f00;
      position: absolute;
      top: 5px;
      left: calc(50% - 2px);
      border-radius: 2px;
      transform-origin: 50% 20px;
    }
    .label {
      font-size: 9px;
      color: #888;
      text-transform: uppercase;
      font-weight: bold;
    }
    .value {
      font-size: 10px;
      color: #fff;
    }
  `;

  @property({ type: String }) label = '';
  @property({ type: Number }) value = 0;
  @property({ type: Number }) min = 0;
  @property({ type: Number }) max = 1;
  @property({ type: Number }) step = 0.01;

  private onPointerDown(e: PointerEvent) {
    const startY = e.clientY;
    const startVal = this.value;

    const onMove = (me: PointerEvent) => {
      const delta = (startY - me.clientY) * (this.max - this.min) / 200;
      let newVal = startVal + delta;
      newVal = Math.max(this.min, Math.min(this.max, newVal));
      if (this.step >= 1) newVal = Math.round(newVal);

      if (newVal !== this.value) {
        this.value = newVal;
        this.dispatchEvent(new CustomEvent('input', { detail: this.value }));
      }
    };

    const onUp = () => {
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };

    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
  }

  // Fix: Removed incorrect override
  render() {
    const range = this.max - this.min;
    const percent = (this.value - this.min) / range;
    const rotation = -135 + (percent * 270);

    return html`
      <div class="knob-container" @pointerdown=${this.onPointerDown}>
        <div class="knob-body">
          <div class="knob-indicator" style="transform: rotate(${rotation}deg)"></div>
        </div>
      </div>
      <div class="label">${this.label}</div>
      <div class="value">${typeof this.value === 'number' ? this.value.toFixed(this.step < 1 ? 2 : 0) : this.value}</div>
    `;
  }
}

import { GoogleGenAI } from '@google/genai';
import './components/LyriaSequencer';
import './components/ToastMessage';
import { LyriaEngine } from './utils/LyriaEngine';
import { AudioAnalyser } from './utils/AudioAnalyser';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const model = 'lyria-realtime-exp';

function main() {
  const engine = new LyriaEngine(ai, model);
  const analyser = new AudioAnalyser(engine.audioContext);
  engine.extraDestination = analyser.node;

  // Create and configure the sequencer
  const sequencer = document.createElement('lyria-sequencer');
  (sequencer as any).engine = engine;
  document.body.appendChild(sequencer);

  // Add toast for feedback
  const toast = document.createElement('toast-message');
  document.body.appendChild(toast);

  engine.addEventListener('error', (e: any) => (toast as any).show(e.detail));
  engine.addEventListener('info', (e: any) => (toast as any).show(e.detail));

  analyser.addEventListener('audio-level-changed', (e: any) => {
    (sequencer as any).audioLevel = e.detail;
  });

  analyser.start();
}

// Start once DOM is ready
if (document.readyState === 'complete') {
  main();
} else {
  window.addEventListener('load', main);
}

