import { GoogleGenAI, LiveMusicSession, LiveMusicServerMessage } from '@google/genai';
import { decode, decodeAudioData } from './audio';
import { throttle } from './throttle';

export class LyriaEngine extends EventTarget {
  private ai: GoogleGenAI;
  private model: string;
  private session: LiveMusicSession | null = null;

  public readonly audioContext: AudioContext;
  private outputNode: GainNode;
  public extraDestination: AudioNode | null = null;

  private nextStartTime = 0;
  private tracks: Map<string, { prompt: string, weight: number }> = new Map();
  private config: any = {
    bpm: 120,
    selectedScale: 'C_MAJOR_A_MINOR',
    guidance: 4.0,
    density: 0.5,
    brightness: 0.5,
    mute_drums: false,
    mute_bass: false,
    only_bass_and_drums: false
  };

  constructor(ai: GoogleGenAI, model: string) {
    super();
    this.ai = ai;
    this.model = model;
    this.audioContext = new AudioContext({ sampleRate: 48000 });
    this.outputNode = this.audioContext.createGain();
  }

  private async connect(): Promise<LiveMusicSession> {
    try {
      const session = await this.ai.live.music.connect({
        model: this.model,
        callbacks: {
          onmessage: async (e: LiveMusicServerMessage) => {
            if (e.serverContent?.audioChunks) {
              const audioBuffer = await decodeAudioData(
                decode(e.serverContent.audioChunks[0].data!),
                this.audioContext,
                48000,
                2
              );
              this.queueAudio(audioBuffer);
            }
          },
          onerror: (err) => {
            console.error("Live API Error", err);
            this.dispatchEvent(new CustomEvent('error', { detail: 'Lyria Connection Error' }));
          },
          onclose: () => this.dispatchEvent(new CustomEvent('info', { detail: 'Session Ended' }))
        }
      });
      return session;
    } catch (e) {
      this.dispatchEvent(new CustomEvent('error', { detail: 'Failed to connect to Lyria' }));
      throw e;
    }
  }

  private queueAudio(buffer: AudioBuffer) {
    const source = this.audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(this.outputNode);

    if (this.nextStartTime < this.audioContext.currentTime) {
      this.nextStartTime = this.audioContext.currentTime + 0.15;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;
  }

  public setTrack(id: string, prompt: string, weight: number) {
    this.tracks.set(id, { prompt, weight });
    this.syncWeights();
  }

  private syncWeights = throttle(async () => {
    if (!this.session) return;
    const weightedPrompts = Array.from(this.tracks.values())
      .filter(t => t.weight > 0 && t.prompt.trim().length > 0)
      .map(t => ({ text: t.prompt, weight: t.weight }));

    if (weightedPrompts.length === 0) return;

    try {
      await this.session.setWeightedPrompts({ weightedPrompts });
    } catch (e) {
      console.warn("Weight sync error", e);
    }
  }, 500);

  public async updateConfig(newConfig: Partial<any>) {
    this.config = { ...this.config, ...newConfig };
  }

  public async play() {
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
    this.outputNode.connect(this.audioContext.destination);
    if (this.extraDestination) this.outputNode.connect(this.extraDestination);

    if (!this.session) {
      this.session = await this.connect();
      await this.session.play({
         config: {
           bpm: Number(this.config.bpm),
           scale: this.config.selectedScale,
           guidance: Number(this.config.guidance),
           density: Number(this.config.density),
           brightness: Number(this.config.brightness),
           mute_drums: this.config.mute_drums,
           mute_bass: this.config.mute_bass,
           only_bass_and_drums: this.config.only_bass_and_drums
         }
      });
      this.syncWeights();
    } else {
      await this.session.play();
    }
  }

  public async stop() {
    if (this.session) {
      await this.session.stop();
      this.session = null;
    }
    this.nextStartTime = 0;
  }

  public async pause() {
    if (this.session) await this.session.pause();
    this.nextStartTime = 0;
  }
}

