          onerror: (err) => {
            console.error("Live API Error", err);
            this.dispatchEvent(new CustomEvent('error', { detail: 'Lyria Connection Error' }));
          },
          onclose: () => this.dispatchEvent(new CustomEvent('info', { detail: 'Session Ended' }))
        }
      });
      return session;
    } catch (e) {
      this.dispatchEvent(new CustomEvent('error', { detail: 'Failed to connect to Lyria' }));
      throw e;
    }
  }

  private queueAudio(buffer: AudioBuffer) {
    const source = this.audioContext.createBufferSource();
    source.buffer = buffer;
    source.connect(this.outputNode);

    if (this.nextStartTime < this.audioContext.currentTime) {
      this.nextStartTime = this.audioContext.currentTime + 0.15;
    }

    source.start(this.nextStartTime);
    this.nextStartTime += buffer.duration;
  }

  public setTrack(id: string, prompt: string, weight: number) {
    this.tracks.set(id, { prompt, weight });
    this.syncWeights();
  }

  private syncWeights = throttle(async () => {
    if (!this.session) return;
    const weightedPrompts = Array.from(this.tracks.values())
      .filter(t => t.weight > 0 && t.prompt.trim().length > 0)
      .map(t => ({ text: t.prompt, weight: t.weight }));

    if (weightedPrompts.length === 0) return;

    try {
      await this.session.setWeightedPrompts({ weightedPrompts });
    } catch (e) {
      console.warn("Weight sync error", e);
    }
  }, 500);

  public async updateConfig(newConfig: Partial<any>) {
    this.config = { ...this.config, ...newConfig };
  }

  public async play() {
    if (this.audioContext.state === 'suspended') {
      await this.audioContext.resume();
    }
    this.outputNode.connect(this.audioContext.destination);
    if (this.extraDestination) this.outputNode.connect(this.extraDestination);

    if (!this.session) {
      this.session = await this.connect();
      // Fix: session.play() does not take arguments. Config is passed during connect.
      await this.session.play();
      this.syncWeights();
    } else {
      await this.session.play();
    }
  }

  public async stop() {
    if (this.session) {
      await this.session.stop();
      this.session = null;
    }
    this.nextStartTime = 0;
  }

  public async pause() {
    if (this.session) await this.session.pause();
    this.nextStartTime = 0;
  }
}

